#!/usr/bin/env python3 import enhanced_rft_crypto import time def test_simple_feistel(): print("Testing simple Enhanced RFT Feistel reversibility...") cipher = enhanced_rft_crypto.PyEnhancedRFTCrypto() # Test with very simple data simple_data = b'12345678' # 8 bytes key = b'key12345678901234567890123456789012' # 32 bytes print(f"Original: {simple_data.hex()}") # Encrypt encrypted = cipher.encrypt(simple_data, key) print(f"Encrypted: {encrypted.hex()}") # Decrypt decrypted = cipher.decrypt(encrypted, key) print(f"Decrypted: {decrypted.hex()}") print(f"Match: {simple_data == decrypted}") # Show differences if simple_data != decrypted: print("Differences:") for i, (orig, dec) in enumerate(zip(simple_data, decrypted)): if orig != dec: print(f" Byte {i}: {orig:02x} -> {dec:02x}") if __name__ == "__main__": test_simple_feistel() 